INSERT INTO cities (slug,name,seo_title,seo_description,h1,intro_text,pickup_points) VALUES
('casablanca','Casablanca','Location voiture Casablanca | Atlas Drive System','Voiture à louer à Casablanca avec livraison aéroport Mohammed V et confirmation WhatsApp.','Location de voiture à Casablanca','Casablanca demande une flotte flexible: trajets d’affaires à Maârif, arrivées tardives à Mohammed V et rendez-vous entre Casa-Port et Anfa. Atlas Drive System met en avant une réservation rapide avec conditions visibles avant confirmation.','Aéroport Mohammed V, Maârif, Casa Voyageurs, Casa-Port, Anfa'),
('marrakech','Marrakech','Location voiture Marrakech | Atlas Drive System','Location voiture Marrakech Menara, Guéliz, Hivernage et Médina avec WhatsApp.','Location de voiture à Marrakech','À Marrakech, les clients alternent souvent entre hôtel, riad, excursions et arrivée à Menara. Cette page privilégie les prises en charge pratiques et les véhicules adaptés aux routes vers l’Ourika, Essaouira ou le centre-ville.','Aéroport Marrakech Menara, Guéliz, Hivernage, Médina'),
('agadir','Agadir','Location voiture Agadir | Atlas Drive System','Louez une voiture à Agadir, Taghazout ou aéroport Al Massira avec conditions transparentes.','Location de voiture à Agadir','Agadir exige une expérience simple pour plage, marina, Taghazout et déplacements depuis Al Massira. Les demandes sont capturées avant WhatsApp pour aider l’agence à suivre chaque prospect sans perdre les conversations.','Aéroport Agadir Al Massira, Marina, Centre-ville, Taghazout');
