CREATE TABLE agencies (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(190) NOT NULL,slug VARCHAR(190) UNIQUE NOT NULL,phone VARCHAR(80),whatsapp_number VARCHAR(80),logo_path VARCHAR(255),address TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE cars (id INT AUTO_INCREMENT PRIMARY KEY,agency_id INT NOT NULL,name VARCHAR(190) NOT NULL,slug VARCHAR(220) UNIQUE NOT NULL,category VARCHAR(80) NOT NULL,transmission VARCHAR(80) NOT NULL,fuel_type VARCHAR(80) NOT NULL,seats INT DEFAULT 5,price_per_day DECIMAL(10,2) NOT NULL,image_path VARCHAR(255),description TEXT,features TEXT,deposit_info TEXT,documents_required TEXT,insurance_info TEXT,status ENUM('available','rented','maintenance','hidden') DEFAULT 'available',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE cities (id INT AUTO_INCREMENT PRIMARY KEY,slug VARCHAR(190) UNIQUE NOT NULL,name VARCHAR(190) NOT NULL,seo_title VARCHAR(255) NOT NULL,seo_description VARCHAR(255) NOT NULL,h1 VARCHAR(255) NOT NULL,intro_text TEXT NOT NULL,pickup_points TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE leads (id INT AUTO_INCREMENT PRIMARY KEY,car_id INT NOT NULL,agency_id INT NOT NULL,full_name VARCHAR(190) NOT NULL,phone VARCHAR(80) NOT NULL,pickup_city VARCHAR(190) NOT NULL,pickup_location VARCHAR(190) NOT NULL,pickup_date DATE NOT NULL,return_date DATE NOT NULL,message TEXT,whatsapp_opened TINYINT(1) DEFAULT 0,status ENUM('new','contacted','confirmed','cancelled') DEFAULT 'new',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE admins (id INT AUTO_INCREMENT PRIMARY KEY,username VARCHAR(190) UNIQUE NOT NULL,password_hash VARCHAR(255) NOT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
